<<<<<<< HEAD
{"version":3,"sources":["pages/home/index.uvue","App.uvue"],"sourcesContent":["<template>\r\n  <view class=\"page\">\r\n    <view class=\"bg-glow glow-purple\"></view>\r\n    <view class=\"bg-glow glow-blue\"></view>\r\n    <view class=\"bg-glow glow-pink\"></view>\r\n    <view class=\"sky-moon\"></view>\r\n    <view class=\"sky-cloud cloud-a\"></view>\r\n    <view class=\"sky-cloud cloud-b\"></view>\r\n    <view class=\"sky-star star-a\"></view>\r\n    <view class=\"sky-star star-b\"></view>\r\n    <view class=\"sky-star star-c\"></view>\r\n    <view class=\"sky-star star-d\"></view>\r\n    <view class=\"sky-star star-e\"></view>\r\n    <view class=\"sky-star star-f\"></view>\r\n    <view class=\"sky-star star-g\"></view>\r\n    <view class=\"sky-star star-h\"></view>\r\n    <view class=\"sky-star star-i\"></view>\r\n    <view class=\"sky-star star-j\"></view>\r\n    <view class=\"sky-star star-k\"></view>\r\n    <view class=\"sky-star star-l\"></view>\r\n    <view class=\"sky-star star-m\"></view>\r\n    <view class=\"sky-star star-n\"></view>\r\n    <view class=\"sky-star star-o\"></view>\r\n    <view class=\"sky-star star-p\"></view>\r\n    <view class=\"sky-star star-q\"></view>\r\n    <view class=\"sky-star star-r\"></view>\r\n    <view class=\"sky-star star-s\"></view>\r\n    <view class=\"sky-star star-t\"></view>\r\n    <scroll-view class=\"scroll-area\" scroll-y=\"true\">\r\n      <view class=\"greeting-bar\">\r\n        <view class=\"greeting-header\">\r\n          <view class=\"greeting-left\">\r\n            <text class=\"brand-kicker\">微憩星球</text>\r\n            <text class=\"greeting-text\">{{ greeting }}</text>\r\n            <text class=\"greeting-date\">{{ dateStr }}</text>\r\n            <text class=\"greeting-hint\">{{ greetingHint }}</text>\r\n          </view>\r\n          <view class=\"greeting-right\">\r\n            <view class=\"mini-planet\" @tap=\"openPhoneDialog\">\r\n              <view class=\"mini-orbit\"></view>\r\n              <view class=\"mini-orbit mini-orbit-back\"></view>\r\n              <view class=\"mini-star mini-star-a\"></view>\r\n              <view class=\"mini-star mini-star-b\"></view>\r\n              <view class=\"mini-satellite\"></view>\r\n              <view class=\"mini-planet-core\">\r\n                <view class=\"mini-planet-shine\"></view>\r\n                <view class=\"mini-planet-halo\"></view>\r\n              </view>\r\n            </view>\r\n            <view class=\"settings-icon\" @tap=\"goSettings\">\r\n              <text class=\"settings-icon-text\">⚙</text>\r\n            </view>\r\n          </view>\r\n        </view>\r\n        <view class=\"phone-usage-hint\" @tap=\"openPhoneDialog\">\r\n          <text class=\"phone-usage-hint-text\">{{ phoneUsageHint }}</text>\r\n        </view>\r\n        <view class=\"hero-action-row\">\r\n          <view class=\"hero-stat-pill\">\r\n            <text class=\"hero-stat-num\">{{ guardCount }}</text>\r\n            <text class=\"hero-stat-label\">次点亮</text>\r\n          </view>\r\n          <view class=\"hero-main-cta\" @tap=\"startHeroAction\">\r\n            <text class=\"hero-main-cta-text\">开始一个微动作</text>\r\n          </view>\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"achievement-section\">\r\n        <view class=\"achievement-header\" @tap=\"toggleAchievementsCollapsed\">\r\n          <view class=\"achievement-title-wrap\">\r\n            <text class=\"achievement-title\">成就栏</text>\r\n            <text class=\"achievement-count\">{{ unlockedCount }} / 12</text>\r\n            <view v-if=\"newUnlockedCount > 0\" class=\"achievement-red-dot\"></view>\r\n          </view>\r\n          <text class=\"achievement-toggle\">{{ achievementsCollapsed ? '展开' : '收起' }}</text>\r\n        </view>\r\n        <view v-if=\"achievementsCollapsed\" class=\"achievement-collapsed-scroll\">\r\n          <scroll-view class=\"achievement-scroll-x\" scroll-x=\"true\" show-scrollbar=\"false\">\r\n            <view v-for=\"(a, i) in achievements\" :key=\"'ac-' + i\" class=\"achv-chip\" :class=\"a.isUnlocked ? 'achv-chip-on' : 'achv-chip-off'\" @tap=\"onAchievementChipTap(a)\">\r\n              <text class=\"achv-chip-icon\">{{ a.def.icon }}</text>\r\n              <text v-if=\"a.isUnlocked\" class=\"achv-chip-mark\">✓</text>\r\n              <text v-else class=\"achv-chip-mark achv-chip-mark-lock\">锁</text>\r\n              <view v-if=\"a.isNew\" class=\"achv-chip-newdot\"></view>\r\n            </view>\r\n          </scroll-view>\r\n        </view>\r\n        <view v-else class=\"achievement-grid\">\r\n          <view v-for=\"(a, i) in achievements\" :key=\"'ag-' + i\" class=\"achv-grid-card\" :class=\"a.isUnlocked ? 'achv-grid-on' : 'achv-grid-off'\" @tap=\"onAchievementGridTap(a)\">\r\n            <text class=\"achv-grid-icon\">{{ a.def.icon }}</text>\r\n            <text class=\"achv-grid-name\">{{ a.def.name }}</text>\r\n            <text class=\"achv-grid-cat\">{{ a.def.category }}</text>\r\n            <text class=\"achv-grid-prog\" v-if=\"a.isUnlocked\">已达成</text>\r\n            <text class=\"achv-grid-prog achv-grid-prog-off\" v-else>{{ a.currentProgress }} / {{ a.def.threshold }}</text>\r\n            <view v-if=\"a.isNew\" class=\"achv-grid-newdot\"></view>\r\n          </view>\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"planet-hero-card\">\r\n        <view class=\"planet-hero-copy\">\r\n          <text class=\"planet-eyebrow\">今日已点亮</text>\r\n          <view class=\"planet-count-row\">\r\n            <text class=\"planet-count\">{{ guardCount }}</text>\r\n            <text class=\"planet-count-unit\">次</text>\r\n          </view>\r\n          <text class=\"planet-guard-text\">{{ guardMinuteText }}</text>\r\n          <text class=\"planet-kind-text\">每一次短暂停顿，都是身体收到的善意</text>\r\n        </view>\r\n        <view class=\"planet-visual\" :class=\"planetVisualClass\">\r\n          <view class=\"planet-ring\" v-if=\"showPlanetRing\"></view>\r\n          <view class=\"planet-core\" :class=\"planetCoreClass\">\r\n            <text class=\"planet-core-text\">✦</text>\r\n          </view>\r\n          <view class=\"planet-particle particle-a\" v-if=\"showPlanetParticles\"></view>\r\n          <view class=\"planet-particle particle-b\" v-if=\"showPlanetParticles\"></view>\r\n          <view class=\"planet-particle particle-c\" v-if=\"showPlanetParticles\"></view>\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"cockpit-grid\">\r\n        <view class=\"health-cluster\">\r\n          <view class=\"section-header-row compact-header\">\r\n            <text class=\"section-title\">三颗健康星球</text>\r\n            <text class=\"section-caption\">护眼 · 体态 · 活力</text>\r\n          </view>\r\n          <StatusIndicator title=\"护眼\" :percent=\"eyeScore\" :status=\"eyeStatus\" />\r\n          <StatusIndicator title=\"体态\" :percent=\"postureScore\" :status=\"postureStatus\" />\r\n          <StatusIndicator title=\"活力\" :percent=\"vitalityScore\" :status=\"vitalityStatus\" />\r\n        </view>\r\n\r\n        <view class=\"cockpit-side\">\r\n          <view class=\"penetration-section\">\r\n            <view class=\"penetration-copy\">\r\n              <text class=\"section-label\">习惯渗透度</text>\r\n              <text class=\"penetration-sub\">星环正在慢慢变亮</text>\r\n            </view>\r\n            <view class=\"penetration-track\">\r\n              <view class=\"penetration-fill\" :style=\"{ width: (penetration * 10 > 100 ? 100 : penetration * 10) + '%' }\"></view>\r\n            </view>\r\n            <text class=\"penetration-value\">{{ penetrationStr }}</text>\r\n          </view>\r\n\r\n          <view class=\"summary-card\" v-if=\"dailySummary != null\">\r\n            <text class=\"summary-eyebrow\">AI 今日判断</text>\r\n            <text class=\"summary-oneliner\">{{ summaryOneLiner }}</text>\r\n            <text v-if=\"summaryBody.length > 0\" class=\"summary-body\">{{ summaryBody }}</text>\r\n            <view v-if=\"summaryGoal.length > 0\" class=\"summary-goal-row\">\r\n              <text class=\"summary-goal-label\">明日轨道</text>\r\n              <text class=\"summary-goal-text\">{{ summaryGoal }}</text>\r\n            </view>\r\n            <text v-if=\"summaryEncourage.length > 0\" class=\"summary-encourage\">{{ summaryEncourage }}</text>\r\n            <view class=\"ai-feedback-row\">\r\n              <view class=\"ai-feedback-chip\"><text class=\"ai-feedback-text\">有帮助</text></view>\r\n              <view class=\"ai-feedback-chip\"><text class=\"ai-feedback-text\">不太准</text></view>\r\n            </view>\r\n          </view>\r\n          <view class=\"summary-card summary-empty\" v-else>\r\n            <text class=\"summary-eyebrow\">AI 今日判断</text>\r\n            <text class=\"summary-empty-text\">{{ summaryPlaceholder }}</text>\r\n            <text class=\"summary-empty-hint\">完成更多微动作后，我会更懂你的节奏</text>\r\n          </view>\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"recommend-section\">\r\n        <view class=\"section-header-row\">\r\n          <text class=\"section-title\">今日推荐动作</text>\r\n          <text class=\"section-caption\">挑一个，让小星球亮一下</text>\r\n        </view>\r\n        <view v-if=\"recommendedActions.length < 1\" class=\"empty-recommend\">\r\n          <text class=\"empty-text\">暂无推荐</text>\r\n        </view>\r\n        <view v-for=\"(action, idx) in recommendedActions\" :key=\"'r-' + idx\" class=\"recommend-item\" :class=\"idx == 0 ? 'recommend-main' : 'recommend-secondary'\">\r\n          <ActionCard\r\n            :action-id=\"action.id\"\r\n            :action-name=\"action.name\"\r\n            :action-duration=\"Math.ceil(action.defaultDurationMs / 1000)\"\r\n            variant=\"recommend\"\r\n            @actionTap=\"startAction\"\r\n          />\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"library-section\">\r\n        <view class=\"library-header\">\r\n          <text class=\"section-title\">小动作仓库（{{ allActions.length }}）</text>\r\n          <text class=\"library-hint\">点选任意动作，给身体一个几秒钟的小空隙</text>\r\n        </view>\r\n        <view v-for=\"(action, idx) in allActions\" :key=\"'a-' + idx\" class=\"library-item\">\r\n          <ActionCard\r\n            :action-id=\"action.id\"\r\n            :action-name=\"action.name\"\r\n            :action-duration=\"Math.ceil(action.defaultDurationMs / 1000)\"\r\n            variant=\"library\"\r\n            @actionTap=\"startAction\"\r\n          />\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"light-record-card\">\r\n        <view class=\"light-record-header\">\r\n          <view class=\"light-record-icon\">\r\n            <text class=\"light-record-icon-text\">✧</text>\r\n          </view>\r\n          <view class=\"light-record-copy\">\r\n            <text class=\"light-record-title\">星球点亮记录</text>\r\n            <text class=\"light-record-text\">每个小格子，都是你照顾自己的一个瞬间。</text>\r\n          </view>\r\n        </view>\r\n        <HeatmapCalendar :dates=\"homeHeatmapDates\" :counts=\"homeHeatmapCounts\" :height=\"260\" />\r\n      </view>\r\n      <LlmHistoryCard :entries=\"llmHistoryEntries\" />\r\n\r\n      <view class=\"bottom-spacer\" />\r\n    </scroll-view>\r\n    <PhoneUsageDialog :visible=\"showPhoneDialog\" @close=\"closePhoneDialog\" />\r\n    <TriggerRuleDialog\r\n      :visible=\"showRuleDialog\"\r\n      :action-name=\"ruleActionName\"\r\n      :time-window-start=\"ruleTimeWindowStart\"\r\n      :time-window-end=\"ruleTimeWindowEnd\"\r\n      :time-threshold-minutes=\"ruleTimeThresholdMinutes\"\r\n      :screen-cond-text=\"ruleScreenCondText\"\r\n      :reasoning=\"pendingReasoning\"\r\n      @close=\"closeRuleDialog\"\r\n      @accept=\"acceptRule\"\r\n      @decline=\"closeRuleDialog\"\r\n      @never-ask=\"neverAskRule\"\r\n    />\r\n    <AchievementDetailDialog\r\n      :visible=\"showAchvDetail\"\r\n      :achievement-icon=\"detailIcon\"\r\n      :achievement-name=\"detailName\"\r\n      :achievement-category=\"detailCat\"\r\n      :achievement-description=\"detailDesc\"\r\n      :is-unlocked=\"detailUnlocked\"\r\n      :unlocked-date=\"detailUnlockedDate\"\r\n      :reward-text=\"detailReward\"\r\n      :progress-text=\"detailProgressText\"\r\n      :progress-percent=\"detailProgressPercent\"\r\n      :history-text=\"detailHistoryText\"\r\n      @close=\"closeAchvDetail\"\r\n    />\r\n    <AchievementUnlockDialog\r\n      :visible=\"showAchvUnlock\"\r\n      :achievement-icon=\"unlockIcon\"\r\n      :achievement-name=\"unlockName\"\r\n      :achievement-description=\"unlockDesc\"\r\n      :reward-text=\"unlockReward\"\r\n      @close=\"onUnlockDismiss\"\r\n      @viewDetail=\"onUnlockViewDetail\"\r\n    />\r\n  </view>\r\n</template>\r\n\r\n<script setup lang=\"uts\">\r\nimport StatusIndicator from '../../components/StatusIndicator.uvue'\r\nimport ActionCard from '../../components/ActionCard.uvue'\r\nimport PhoneUsageDialog from '../../components/PhoneUsageDialog.uvue'\r\nimport LlmHistoryCard from '../../components/LlmHistoryCard.uvue'\r\nimport TriggerRuleDialog from '../../components/TriggerRuleDialog.uvue'\r\nimport HeatmapCalendar from '../../components/HeatmapCalendar.uvue'\r\nimport { useAppStore, DailyOutput } from '../../stores/appStore'\r\nimport { MicroAction } from '../../models/MicroAction'\r\nimport { LlmHistoryEntry } from '../../models/LlmHistoryEntry'\r\nimport { EffectiveTriggerRule, ScreenConditions } from '../../models/EffectiveTriggerRule'\r\nimport { AchievementItem } from '../../models/Achievement'\r\nimport { currentHour } from '../../utils/TimeUtils'\r\nimport { getEnabledActions } from '../../services/ActionManager'\r\nimport { getSetting, putBool, getInt, putInt, putSetting } from '../../database/SettingsDao'\r\nimport { setActionIdForNextPage } from '../../utils/NavigationHelper'\r\nimport { getActionById } from '../../constants/Actions'\r\nimport { getGreetingHint } from '../../constants/MicroPlanetCopy'\r\nimport { getAchievementDef } from '../../constants/Achievements'\r\nimport { getProgressText as computeProgressText } from '../../services/AchievementService'\r\nimport AchievementDetailDialog from '../../components/AchievementDetailDialog.uvue'\r\nimport AchievementUnlockDialog from '../../components/AchievementUnlockDialog.uvue'\r\n\r\nconst store = useAppStore()\r\nconst nowMs = ref<number>(Date.now())\r\nconst nowHour = ref<number>(currentHour())\r\nlet clockTimerId: number | null = null\r\n\r\nconst eyeScore = computed<number>(() : number => store.eyeScore.value)\r\nconst eyeStatus = computed<string>(() : string => store.eyeStatus.value)\r\nconst postureScore = computed<number>(() : number => store.postureScore.value)\r\nconst postureStatus = computed<string>(() : string => store.postureStatus.value)\r\nconst vitalityScore = computed<number>(() : number => store.vitalityScore.value)\r\nconst vitalityStatus = computed<string>(() : string => store.vitalityStatus.value)\r\nconst guardCount = computed<number>(() : number => store.guardCount.value)\r\nconst penetration = computed<number>(() : number => store.penetration.value)\r\nconst penetrationStr = computed<string>(() : string => penetration.value.toFixed(1))\r\nconst recommendedActions = computed<MicroAction[]>(() => store.recommendedActions.value)\r\nconst allActions = computed<MicroAction[]>(() => getEnabledActions())\r\n\r\nconst achievements = computed<AchievementItem[]>(() : AchievementItem[] => store.achievements.value)\r\nconst achievementsCollapsed = ref<boolean>(getInt('achievements_collapsed', 1) == 1)\r\nconst seenSet = ref<Set<string>>(new Set<string>())\r\n\r\nconst unlockedCount = computed<number>(() : number => {\r\n  let n = 0\r\n  for (let i = 0; i < achievements.value.length; i++) {\r\n    const item = achievements.value[i]\r\n    if (item != null && item.isUnlocked) n++\r\n  }\r\n  return n\r\n})\r\n\r\nconst newUnlockedCount = computed<number>(() : number => {\r\n  let n = 0\r\n  for (let i = 0; i < achievements.value.length; i++) {\r\n    const item = achievements.value[i]\r\n    if (item != null && item.isUnlocked && !seenSet.value.has(item.def.id)) n++\r\n  }\r\n  return n\r\n})\r\n\r\nfunction refreshSeenSet(): void {\r\n  try {\r\n    const raw = getSetting('seen_achievements', '[]')\r\n    const arr = JSON.parse(raw) as Array<any>\r\n    const s = new Set<string>()\r\n    if (arr != null) {\r\n      for (let i = 0; i < arr.length; i++) {\r\n        const v = arr[i]\r\n        if (typeof v === 'string' && (v as string).length > 0) {\r\n          s.add(v as string)\r\n        }\r\n      }\r\n    }\r\n    seenSet.value = s\r\n  } catch (_) {\r\n    seenSet.value = new Set<string>()\r\n  }\r\n}\r\n\r\nfunction markAchievementSeen(id: string): void {\r\n  const s = seenSet.value\r\n  s.add(id)\r\n  const arr: string[] = []\r\n  s.forEach((v: string): void => { arr.push(v) })\r\n  const json = '[' + arr.map((v: string): string => '\"' + v + '\"').join(',') + ']'\r\n  try { putSetting('seen_achievements', json) } catch (_) {}\r\n}\r\n\r\nconst showAchvDetail = ref<boolean>(false)\r\nconst detailItem = ref<AchievementItem | null>(null)\r\nconst detailIcon = ref<string>('')\r\nconst detailName = ref<string>('')\r\nconst detailCat = ref<string>('')\r\nconst detailDesc = ref<string>('')\r\nconst detailUnlocked = ref<boolean>(false)\r\nconst detailUnlockedDate = ref<string>('')\r\nconst detailReward = ref<string>('')\r\nconst detailProgressText = ref<string>('')\r\nconst detailProgressPercent = ref<number>(0)\r\nconst detailHistoryText = ref<string>('')\r\n\r\nconst showAchvUnlock = ref<boolean>(false)\r\nconst unlockIcon = ref<string>('')\r\nconst unlockName = ref<string>('')\r\nconst unlockDesc = ref<string>('')\r\nconst unlockReward = ref<string>('')\r\nconst unlockCurrentId = ref<string>('')\r\n\r\nfunction toggleAchievementsCollapsed(): void {\r\n  achievementsCollapsed.value = !achievementsCollapsed.value\r\n  try { putInt('achievements_collapsed', achievementsCollapsed.value ? 1 : 0) } catch (_) {}\r\n}\r\n\r\nfunction openAchvDetail(item: AchievementItem): void {\r\n  detailItem.value = item\r\n  detailIcon.value = item.def.icon\r\n  detailName.value = item.def.name\r\n  detailCat.value = item.def.category\r\n  detailDesc.value = item.def.description\r\n  detailUnlocked.value = item.isUnlocked\r\n  if (item.isUnlocked && item.unlockedAt > 0) {\r\n    const d = new Date(item.unlockedAt * 1000)\r\n    detailUnlockedDate.value = d.getFullYear() + '-' + ('' + (d.getMonth() + 1)).padStart(2, '0') + '-' + ('' + d.getDate()).padStart(2, '0')\r\n  } else {\r\n    detailUnlockedDate.value = ''\r\n  }\r\n  detailReward.value = item.def.rewardText\r\n  const prog = computeProgressText(item)\r\n  detailProgressText.value = prog.text\r\n  detailProgressPercent.value = prog.percent\r\n  detailHistoryText.value = item.def.historyText\r\n  showAchvDetail.value = true\r\n}\r\n\r\nfunction closeAchvDetail(): void {\r\n  showAchvDetail.value = false\r\n  detailItem.value = null\r\n}\r\n\r\nfunction tryShowNextUnlock(): void {\r\n  const pending = store.pendingUnlockIds.value\r\n  if (pending.length < 1) return\r\n  const firstId = pending[0] as string\r\n  const def = getAchievementDef(firstId)\r\n  if (def == null) {\r\n    store.shiftPendingUnlock()\r\n    tryShowNextUnlock()\r\n    return\r\n  }\r\n  unlockIcon.value = def.icon\r\n  unlockName.value = def.name\r\n  unlockDesc.value = def.description\r\n  unlockReward.value = def.rewardText\r\n  unlockCurrentId.value = firstId\r\n  showAchvUnlock.value = true\r\n}\r\n\r\nfunction onUnlockDismiss(): void {\r\n  if (unlockCurrentId.value.length > 0) {\r\n    markAchievementSeen(unlockCurrentId.value)\r\n  }\r\n  showAchvUnlock.value = false\r\n  unlockCurrentId.value = ''\r\n  store.shiftPendingUnlock()\r\n  setTimeout((): void => {\r\n    tryShowNextUnlock()\r\n  }, 200)\r\n}\r\n\r\nfunction onUnlockViewDetail(): void {\r\n  const firstId = unlockCurrentId.value\r\n  if (firstId.length > 0) {\r\n    markAchievementSeen(firstId)\r\n  }\r\n  showAchvUnlock.value = false\r\n  unlockCurrentId.value = ''\r\n  store.shiftPendingUnlock()\r\n  setTimeout((): void => {\r\n    for (let i = 0; i < achievements.value.length; i++) {\r\n      const item = achievements.value[i]\r\n      if (item != null && item.def.id == firstId) {\r\n        openAchvDetail(item)\r\n        break\r\n      }\r\n    }\r\n    tryShowNextUnlock()\r\n  }, 200)\r\n}\r\n\r\nfunction onAchievementChipTap(item: AchievementItem): void {\r\n  if (item.isNew) markAchievementSeen(item.def.id)\r\n  openAchvDetail(item)\r\n}\r\n\r\nfunction onAchievementGridTap(item: AchievementItem): void {\r\n  if (item.isNew) markAchievementSeen(item.def.id)\r\n  openAchvDetail(item)\r\n}\r\n\r\nfunction getHomeHeatmapDates(): string[] {\r\n  const rows = store.heatmapData.value\r\n  const out: string[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    const item = rows[i]\r\n    if (item != null) out.push(item.date)\r\n  }\r\n  return out\r\n}\r\n\r\nfunction getHomeHeatmapCounts(): number[] {\r\n  const rows = store.heatmapData.value\r\n  const out: number[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    const item = rows[i]\r\n    if (item != null) out.push(item.count)\r\n  }\r\n  return out\r\n}\r\n\r\nconst homeHeatmapDates = computed<string[]>(getHomeHeatmapDates)\r\nconst homeHeatmapCounts = computed<number[]>(getHomeHeatmapCounts)\r\n\r\nconst dailySummary = computed<DailyOutput | null>(() : DailyOutput | null => store.dailySummary.value)\r\nconst dailySummaryLoading = computed<boolean>(() : boolean => store.dailySummaryLoading.value)\r\nfunction getSummaryOneLiner(): string {\r\n  const s = dailySummary.value\r\n  return s != null && s.bodyText.length > 0 ? '今日小结已生成' : '今日小结待生成'\r\n}\r\nfunction getSummaryBody(): string {\r\n  const s = dailySummary.value\r\n  return s != null ? s.bodyText : ''\r\n}\r\nfunction getSummaryGoal(): string {\r\n  return ''\r\n}\r\nfunction getSummaryEncourage(): string {\r\n  return ''\r\n}\r\nfunction getSummaryHour(): number {\r\n  const raw = getSetting('daily_summary_time', '21:00')\r\n  const sep = raw.indexOf(':')\r\n  const h = parseInt(sep > 0 ? raw.substring(0, sep) : raw)\r\n  if (h < 0 || h > 23) return 21\r\n  return h\r\n}\r\nfunction getSummaryPlaceholder(): string {\r\n  if (dailySummaryLoading.value) return '正在生成今日小结…'\r\n  const cnt = store.todayCompletedCount.value\r\n  if (cnt < 1) return '完成一个微动作，开启今日小结'\r\n  return '已完成' + cnt + '次，' + getSummaryHour() + ':00 后自动小结'\r\n}\r\n\r\nconst summaryOneLiner = computed<string>(getSummaryOneLiner)\r\nconst summaryBody = computed<string>(getSummaryBody)\r\nconst summaryGoal = computed<string>(getSummaryGoal)\r\nconst summaryEncourage = computed<string>(getSummaryEncourage)\r\nconst summaryHour = computed<number>(getSummaryHour)\r\nconst summaryPlaceholder = computed<string>(getSummaryPlaceholder)\r\n\r\nfunction getGreeting(): string {\r\n  const h = nowHour.value\r\n  if (h < 6) return '夜深了'\r\n  if (h < 9) return '早上好'\r\n  if (h < 12) return '上午好'\r\n  if (h < 14) return '中午好'\r\n  if (h < 18) return '下午好'\r\n  if (h < 22) return '晚上好'\r\n  return '夜深了'\r\n}\r\n\r\nfunction getGreetingEmoji(): string {\r\n  const h = nowHour.value\r\n  if (h < 6) return '🌙'\r\n  if (h < 9) return '☀️'\r\n  if (h < 12) return '☀️'\r\n  if (h < 14) return '🌤'\r\n  if (h < 18) return '⛅'\r\n  if (h < 22) return '🌆'\r\n  return '🌙'\r\n}\r\n\r\nconst greeting = computed<string>(getGreeting)\r\nconst greetingEmoji = computed<string>(getGreetingEmoji)\r\nconst greetingHint = computed<string>(() : string => getGreetingHint(nowHour.value))\r\n\r\nconst phoneMinutes = computed<number>(() : number => store.phoneMinutes.value)\r\nfunction getPhoneUsageHint(): string {\r\n  if (phoneMinutes.value < 1) return '点击查看今日手机使用信号'\r\n  return '今日已使用 ' + phoneMinutes.value + ' 分钟，看看星球信号'\r\n}\r\nconst phoneUsageHint = computed<string>(getPhoneUsageHint)\r\n\r\nfunction getGuardMinuteText(): string {\r\n  if (guardCount.value < 1) return '今天的小星球还在等第一次点亮'\r\n  return '已为你守护约 ' + guardCount.value + ' 分钟'\r\n}\r\n\r\nfunction getPlanetVisualClass(): string {\r\n  const count = guardCount.value\r\n  if (count < 1) return 'planet-dim'\r\n  if (count < 4) return 'planet-soft'\r\n  if (count < 9) return 'planet-ring-on'\r\n  return 'planet-bright'\r\n}\r\n\r\nfunction getPlanetCoreClass(): string {\r\n  if (guardCount.value < 1) return 'planet-core-dim'\r\n  return 'planet-core-on'\r\n}\r\n\r\nfunction getShowPlanetRing(): boolean {\r\n  return guardCount.value >= 4\r\n}\r\n\r\nfunction getShowPlanetParticles(): boolean {\r\n  return guardCount.value >= 9\r\n}\r\n\r\nconst guardMinuteText = computed<string>(getGuardMinuteText)\r\nconst planetVisualClass = computed<string>(getPlanetVisualClass)\r\nconst planetCoreClass = computed<string>(getPlanetCoreClass)\r\nconst showPlanetRing = computed<boolean>(getShowPlanetRing)\r\nconst showPlanetParticles = computed<boolean>(getShowPlanetParticles)\r\n\r\nconst showPhoneDialog = ref<boolean>(false)\r\nconst showRuleDialog = ref<boolean>(false)\r\nconst pendingRule = ref<EffectiveTriggerRule | null>(null)\r\nconst pendingReasoning = ref<string>('')\r\n\r\nconst ruleActionName = computed<string>(() : string => {\r\n  const r = pendingRule.value\r\n  if (r == null) return ''\r\n  const a = getActionById(r.actionId)\r\n  return a != null ? a.name : '微动作'\r\n})\r\nconst ruleTimeWindowStart = computed<string>(() : string => {\r\n  const r = pendingRule.value\r\n  if (r == null || r.timeWindow == null) return ''\r\n  return r.timeWindow.start\r\n})\r\nconst ruleTimeWindowEnd = computed<string>(() : string => {\r\n  const r = pendingRule.value\r\n  if (r == null || r.timeWindow == null) return ''\r\n  return r.timeWindow.end\r\n})\r\nconst ruleTimeThresholdMinutes = computed<number>(() : number => {\r\n  const r = pendingRule.value\r\n  if (r == null) return 0\r\n  return r.timeThresholdMinutes\r\n})\r\nconst ruleScreenCondText = computed<string>(() : string => {\r\n  const r = pendingRule.value\r\n  if (r == null || r.screenConditions == null) return ''\r\n  const sc = r.screenConditions\r\n  const parts: string[] = []\r\n  if (sc.includeHome) parts.push('桌面')\r\n  if (sc.appPackages.length > 0) parts.push(sc.appPackages.join(', '))\r\n  return parts.length > 0 ? parts.join(' / ') : '任意'\r\n})\r\n\r\nconst llmHistoryEntries = computed<LlmHistoryEntry[]>(() : LlmHistoryEntry[] => store.llmHistory.value)\r\n\r\nfunction openPhoneDialog(): void {\r\n  showPhoneDialog.value = true\r\n}\r\n\r\nfunction closePhoneDialog(): void {\r\n  showPhoneDialog.value = false\r\n}\r\n\r\nfunction closeRuleDialog(): void {\r\n  showRuleDialog.value = false\r\n  pendingRule.value = null\r\n  pendingReasoning.value = ''\r\n}\r\n\r\nfunction acceptRule(): void {\r\n  showRuleDialog.value = false\r\n  pendingRule.value = null\r\n  pendingReasoning.value = ''\r\n  uni.showToast({ title: '规则已接受（持久化待 Day 5）', icon: 'none' })\r\n}\r\n\r\nfunction neverAskRule(): void {\r\n  putBool('llm_trigger_ask_each_time', false)\r\n  closeRuleDialog()\r\n  uni.showToast({ title: '已关闭\"每次问询\"', icon: 'none' })\r\n}\r\n\r\nfunction getGreetingClass(): string {\r\n  const h = nowHour.value\r\n  if (h < 6) return 'bg-night'\r\n  if (h < 9) return 'bg-morning'\r\n  if (h < 14) return 'bg-noon'\r\n  if (h < 18) return 'bg-afternoon'\r\n  if (h < 22) return 'bg-evening'\r\n  return 'bg-night'\r\n}\r\n\r\nfunction getDateStr(): string {\r\n  const tick = nowMs.value\r\n  if (tick < 1) return ''\r\n  const d = new Date()\r\n  const m = d.getMonth() + 1\r\n  const day = d.getDate()\r\n  const weekDays: string[] = ['日', '一', '二', '三', '四', '五', '六']\r\n  return m + '月' + day + '日 · 星期' + weekDays[d.getDay()]\r\n}\r\n\r\nconst greetingClass = computed<string>(getGreetingClass)\r\nconst dateStr = computed<string>(getDateStr)\r\n\r\nfunction refreshClock(): void {\r\n  nowMs.value = Date.now()\r\n  nowHour.value = currentHour()\r\n}\r\n\r\nfunction clearClockTimer(): void {\r\n  const tid = clockTimerId\r\n  if (tid != null) {\r\n    clearInterval(tid)\r\n    clockTimerId = null\r\n  }\r\n}\r\n\r\nfunction startClockTimer(): void {\r\n  clearClockTimer()\r\n  clockTimerId = setInterval((): void => {\r\n    refreshClock()\r\n  }, 60000)\r\n}\r\n\r\nonPageShow(() => {\r\n  refreshClock()\r\n  store.refreshHomeData()\r\n  store.refreshLlmHistory()\r\n  refreshSeenSet()\r\n  store.refreshAchievements()\r\n  setTimeout((): void => {\r\n    tryShowNextUnlock()\r\n  }, 500)\r\n})\r\n\r\nfunction startAction(actionId: string): void {\r\n  setActionIdForNextPage(actionId)\r\n  uni.navigateTo({\r\n    url: '/pages/action/execute?actionId=' + actionId\r\n  })\r\n}\r\n\r\nfunction startHeroAction(): void {\r\n  const list = recommendedActions.value\r\n  if (list.length > 0) {\r\n    const first = list[0]\r\n    if (first != null) {\r\n      startAction(first.id)\r\n      return\r\n    }\r\n  }\r\n  const all = allActions.value\r\n  if (all.length > 0) {\r\n    const firstAll = all[0]\r\n    if (firstAll != null) startAction(firstAll.id)\r\n  }\r\n}\r\n\r\nfunction goSettings(): void {\r\n  uni.switchTab({\r\n    url: '/pages/settings/index'\r\n  })\r\n}\r\n\r\nonLoad((): void => {\r\n  refreshClock()\r\n  startClockTimer()\r\n  try {\r\n    uni.$on('showTriggerRuleDialog', (data: any): void => {\r\n      try {\r\n        if (data == null) return\r\n        const obj = data as UTSJSONObject\r\n        if (obj == null) return\r\n        const ruleRaw = obj['rule']\r\n        const reasoningRaw = obj['reasoning']\r\n        const ruleStr = JSON.stringify(ruleRaw)\r\n        const rule = JSON.parse(ruleStr) as EffectiveTriggerRule\r\n        if (rule == null) return\r\n        pendingRule.value = rule\r\n        const reasoning = typeof reasoningRaw === 'string' ? (reasoningRaw as string) : ''\r\n        pendingReasoning.value = reasoning\r\n        showRuleDialog.value = true\r\n      } catch (e) {\r\n        console.warn('[home] showTriggerRuleDialog 处理异常: ' + JSON.stringify(e))\r\n      }\r\n    })\r\n  } catch (e) {\r\n    console.warn('[home] $on showTriggerRuleDialog 异常: ' + JSON.stringify(e))\r\n  }\r\n  try {\r\n    uni.$on('pendingAchievementUnlock', (data: any): void => {\r\n      try {\r\n        if (data == null) return\r\n        const obj = data as UTSJSONObject\r\n        if (obj == null) return\r\n        const idsRaw = obj['ids']\r\n        if (idsRaw == null) return\r\n        const idsStr = JSON.stringify(idsRaw)\r\n        const ids = JSON.parse(idsStr) as Array<any>\r\n        if (ids == null || ids.length < 1) return\r\n        const idArr: string[] = []\r\n        for (let i = 0; i < ids.length; i++) {\r\n          const v = ids[i]\r\n          if (typeof v === 'string' && (v as string).length > 0) {\r\n            idArr.push(v as string)\r\n          }\r\n        }\r\n        if (idArr.length > 0) {\r\n          store.setPendingUnlocks(idArr)\r\n          tryShowNextUnlock()\r\n        }\r\n      } catch (e) {\r\n        console.warn('[home] pendingAchievementUnlock 异常: ' + JSON.stringify(e))\r\n      }\r\n    })\r\n  } catch (e) {\r\n    console.warn('[home] $on pendingAchievementUnlock 异常: ' + JSON.stringify(e))\r\n  }\r\n})\r\n\r\nonUnload((): void => {\r\n  clearClockTimer()\r\n})\r\n</script>\r\n\r\n\r\n\r\n<style scoped>\r\n.page {\r\n  flex: 1;\r\n  background-color: #F5F6FA;\r\n}\r\n.scroll-area {\r\n  flex: 1;\r\n}\r\n.greeting-bar {\r\n  flex-direction: column;\r\n  padding: 56px 20px 0 20px;\r\n  background-color: #2C3E50;\r\n}\r\n.greeting-header {\r\n  flex-direction: row;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  padding-bottom: 12px;\r\n}\r\n.bg-morning {\r\n  background-color: #A93226;\r\n}\r\n.bg-noon {\r\n  background-color: #1A5490;\r\n}\r\n.bg-afternoon {\r\n  background-color: #8B4513;\r\n}\r\n.bg-evening {\r\n  background-color: #1A237E;\r\n}\r\n.bg-night {\r\n  background-color: #1B2631;\r\n}\r\n.greeting-left {\r\n  flex-dir